const iterations = $.steps.fetchEmails.response.iterations || [];
let emailSummary = '';
let emailCount = 0;

iterations.forEach(iter => {
  const resp = iter.getEmail ? iter.getEmail.response : null;
  if (!resp) return;
  const headers = (resp.payload && resp.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || '';
  const from = (headers.find(h => h.name === 'From') || {}).value || '';
  const date = (headers.find(h => h.name === 'Date') || {}).value || '';
  emailSummary += date + ' | ' + from + ' | ' + subject + '\n';
  emailCount++;
});

return { emailSummary, emailCount };

const data = $.steps.compileEmailData.output;
const rate = $.input.hourlyRate || 0;

const prompt = 'You are a professional time tracking assistant. Analyze these email records and generate a timesheet.

EMAIL ACTIVITY LOG (' + data.emailCount + ' emails):
' + data.emailSummary + '

INSTRUCTIONS:
- Group related emails into work activities/projects
- Estimate time spent on each activity based on email volume and complexity
- Categorize each activity (Meeting, Communication, Development, Admin, Research, Review)
- Assign reasonable time estimates (0.25h minimum increments)
' + (rate > 0 ? '- Calculate billing at $' + rate + '/hour
' : '') + '
Return ONLY valid JSON:
{
  "timesheetEntries": [
    {
      "date": "YYYY-MM-DD",
      "project": "project or client name",
      "activity": "activity description",
      "category": "Meeting/Communication/Development/Admin/Research/Review",
      "hours": 0.0,
      "notes": "brief notes"
    }
  ],
  "totalHours": 0.0,
  "totalBilling": 0.0,
  "summary": "weekly work summary in 2-3 sentences",
  "topProjects": [{ "name": "project", "hours": 0.0 }]
}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { timesheetEntries: [], totalHours: 0, summary: raw.slice(0, 300) }; }

const ai = $.steps.parseAI.output;
const entries = ai.timesheetEntries || [];
const rate = $.input.hourlyRate || 0;
const rows = entries.map(e => [
  e.date || '',
  e.project || '',
  e.activity || '',
  e.category || '',
  e.hours || 0,
  rate > 0 ? (e.hours * rate).toFixed(2) : '',
  e.notes || ''
]);
const slackText = 'Timesheet generated: ' + entries.length + ' entries | ' + (ai.totalHours || 0) + ' total hours' + (rate > 0 ? ' | $' + (ai.totalBilling || (ai.totalHours * rate)).toFixed(2) + ' billing' : '') + '\n' + (ai.summary || '');
return { rows, slackText };
